const ReportingSalesTotalsFiltered = `-- name: ReportingSalesTotalsFiltered :one

SELECT
    COALESCE(SUM(o.total_minor), 0)::bigint AS gross_total_minor,
    COALESCE(SUM(o.tax_minor), 0)::bigint AS tax_minor,
    COALESCE(SUM(o.subtotal_minor), 0)::bigint AS subtotal_minor,
    COUNT(*)::bigint AS order_count
FROM
    orders o
    INNER JOIN machines m ON m.id = o.machine_id
WHERE
    o.organization_id = $1
    AND o.created_at >= $2::timestamptz
    AND o.created_at < $3::timestamptz
    AND (
        $4::uuid = '00000000-0000-0000-0000-000000000000'::uuid
        OR m.site_id = $4::uuid)
    AND (
        $5::uuid = '00000000-0000-0000-0000-000000000000'::uuid
        OR o.machine_id = $5::uuid)
    AND (
        $6::uuid = '00000000-0000-0000-0000-000000000000'::uuid
        OR EXISTS (
            SELECT
                1
            FROM
                vend_sessions vs
            WHERE
                vs.order_id = o.id
                AND vs.product_id = $6::uuid))
`

type ReportingSalesTotalsFilteredParams struct {
	OrganizationID uuid.UUID
	Column2        time.Time
	Column3        time.Time
	Column4        uuid.UUID
	Column5        uuid.UUID
	Column6        uuid.UUID
}

type ReportingSalesTotalsFilteredRow struct {
	GrossTotalMinor int64
	TaxMinor        int64
	SubtotalMinor   int64
	OrderCount      int64
}

// Filtered sales/payments (site, machine, product) for admin reports. Sentinel nil UUID = unset.
func (q *Queries) ReportingSalesTotalsFiltered(ctx context.Context, arg ReportingSalesTotalsFilteredParams) (ReportingSalesTotalsFilteredRow, error) {
	row := q.db.QueryRow(ctx, ReportingSalesTotalsFiltered,
		arg.OrganizationID,
		arg.Column2,
		arg.Column3,
		arg.Column4,
		arg.Column5,
		arg.Column6,
	)
	var i ReportingSalesTotalsFilteredRow
	err := row.Scan(
		&i.GrossTotalMinor,
		&i.TaxMinor,
		&i.SubtotalMinor,
		&i.OrderCount,
	)
	return i, err
}

