const ReportingVendSummaryTotals = `-- name: ReportingVendSummaryTotals :one
SELECT
    COUNT(*) FILTER (
        WHERE
            vs.state = 'success'
    )::bigint AS success_count,
    COUNT(*) FILTER (
        WHERE
            vs.state = 'failed'
    )::bigint AS failed_count,
    COUNT(*) FILTER (
        WHERE
            vs.state IN ('pending', 'in_progress')
    )::bigint AS in_progress_count
FROM
    vend_sessions vs
    INNER JOIN orders o ON o.id = vs.order_id
    INNER JOIN machines m ON m.id = o.machine_id
WHERE
    o.organization_id = $1
    AND COALESCE(vs.completed_at, vs.created_at) >= $2::timestamptz
    AND COALESCE(vs.completed_at, vs.created_at) < $3::timestamptz
    AND (
        $4::uuid = '00000000-0000-0000-0000-000000000000'::uuid
        OR m.site_id = $4::uuid)
    AND (
        $5::uuid = '00000000-0000-0000-0000-000000000000'::uuid
        OR o.machine_id = $5::uuid)
    AND (
        $6::uuid = '00000000-0000-0000-0000-000000000000'::uuid
        OR vs.product_id = $6::uuid)
`

type ReportingVendSummaryTotalsParams struct {
	OrganizationID uuid.UUID
	Column2        time.Time
	Column3        time.Time
	Column4        uuid.UUID
	Column5        uuid.UUID
	Column6        uuid.UUID
}

type ReportingVendSummaryTotalsRow struct {
	SuccessCount    int64
	FailedCount     int64
	InProgressCount int64
}

func (q *Queries) ReportingVendSummaryTotals(ctx context.Context, arg ReportingVendSummaryTotalsParams) (ReportingVendSummaryTotalsRow, error) {
	row := q.db.QueryRow(ctx, ReportingVendSummaryTotals,
		arg.OrganizationID,
		arg.Column2,
		arg.Column3,
		arg.Column4,
		arg.Column5,
		arg.Column6,
	)
	var i ReportingVendSummaryTotalsRow
	err := row.Scan(&i.SuccessCount, &i.FailedCount, &i.InProgressCount)
	return i, err
}
